i = random.randrange(999)


def get_fair_mines(initial: tuple[int, int]):
    global i

    # reverse of: initial = pos_idx // 13, pos_idx % 13
    pos_idx = initial[0] * 13 + initial[1]

    fun = globals()[f"get_boards_{pos_idx}"]

    boards = fun()

    i = (i + 1) % len(boards)

    board = boards[i]

    assert initial not in board

    return board
